import{_ as n,C as t,c as l,o as p,j as a,G as r,a8 as o,a as i}from"./chunks/framework.DMZhn_gK.js";const E=JSON.parse('{"title":"Spring Boot 启动失败：Invalid empty profile 与 spring.profiles.active","description":"","frontmatter":{},"headers":[],"relativePath":"java/JVM-BUG.md","filePath":"java/JVM-BUG.md","lastUpdated":1776151933000}'),d={name:"java/JVM-BUG.md"};function c(h,s,g,k,u,m){const e=t("ArticleMetadata");return p(),l("div",null,[s[0]||(s[0]=a("h1",{id:"spring-boot-启动失败-invalid-empty-profile-与-spring-profiles-active",tabindex:"-1"},[i("Spring Boot 启动失败："),a("code",null,"Invalid empty profile"),i(" 与 "),a("code",null,"spring.profiles.active"),i(),a("a",{class:"header-anchor",href:"#spring-boot-启动失败-invalid-empty-profile-与-spring-profiles-active","aria-label":'Permalink to "Spring Boot 启动失败：`Invalid empty profile` 与 `spring.profiles.active`"'},"​")],-1)),r(e),s[1]||(s[1]=o(`<h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>应用启动时报错，日志类似：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>APPLICATION FAILED TO START</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Failed to bind properties under &#39;spring.profiles.active&#39; to java.util.Set&lt;java.lang.String&gt;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Property: spring.profiles.active</span></span>
<span class="line"><span>    Value: &quot;</span></span>
<span class="line"><span>&quot;</span></span>
<span class="line"><span>    Origin: &quot;spring.profiles.active&quot; from property source &quot;systemProperties&quot;</span></span>
<span class="line"><span>    Reason: java.lang.IllegalStateException: Invalid empty profile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>要点：</p><ul><li>绑定失败的是 <strong><code>spring.profiles.active</code></strong>。</li><li><strong>属性来源是 <code>systemProperties</code></strong>（JVM 系统属性），不是 <code>application.yaml</code> / <code>application.properties</code>。</li><li>实际传入的值等价于<strong>空或仅空白</strong>（日志里可能显示成奇怪的引号或换行），Spring Boot 不允许“空 profile”，因此抛出 <code>Invalid empty profile</code>。</li></ul><h2 id="容易产生的误解" tabindex="-1">容易产生的误解 <a class="header-anchor" href="#容易产生的误解" aria-label="Permalink to &quot;容易产生的误解&quot;">​</a></h2><p>项目里 <code>src/main/resources/application.yaml</code> 已正确配置，例如：</p><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  profiles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    active</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>若仍出现上述错误，<strong>不一定是 YAML 写错</strong>。Spring Boot 配置有<strong>优先级</strong>：来自 <strong>JVM 系统属性</strong> 或 <strong>环境变量</strong> 的 <code>spring.profiles.active</code> 会覆盖 YAML 中的默认值。若外部传入的是“空 profile”，就会失败，且报错会指向 <strong><code>systemProperties</code></strong> 或对应环境变量源。</p><h2 id="根因说明-本仓库实例" tabindex="-1">根因说明（本仓库实例） <a class="header-anchor" href="#根因说明-本仓库实例" aria-label="Permalink to &quot;根因说明（本仓库实例）&quot;">​</a></h2><p>在 IntelliJ IDEA 的 <strong>Spring Boot 运行配置</strong> 中，<code>OrangeSystemApplication</code> 曾包含：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ACTIVE_PROFILES&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&amp;#10;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>&amp;#10;</code> 表示<strong>换行符</strong>。效果等价于在 IDE 的 <strong>Active profiles</strong> 输入框里只按了回车、没有填写 <code>dev</code>。IDE 仍会向 JVM 传入 <code>spring.profiles.active</code>，值为空白，从而触发 <strong>Invalid empty profile</strong>，并覆盖 <code>application.yaml</code> 里的 <code>active: dev</code>。</p><p>配置文件位置（本仓库）：<code>.idea/workspace.xml</code> 中对应 <code>&lt;configuration name=&quot;OrangeSystemApplication&quot; ...&gt;</code> 节点。</p><h2 id="解决办法" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法" aria-label="Permalink to &quot;解决办法&quot;">​</a></h2><h3 id="_1-在-intellij-中修正运行配置-推荐日常操作" tabindex="-1">1. 在 IntelliJ 中修正运行配置（推荐日常操作） <a class="header-anchor" href="#_1-在-intellij-中修正运行配置-推荐日常操作" aria-label="Permalink to &quot;1. 在 IntelliJ 中修正运行配置（推荐日常操作）&quot;">​</a></h3><ol><li>打开 <strong>Run | Edit Configurations…</strong>。</li><li>选中 <strong>Spring Boot → OrangeSystemApplication</strong>（或你的模块名）。</li><li><strong>Active profiles</strong>： <ul><li>填 <strong><code>dev</code></strong>（与 YAML 一致），或</li><li><strong>完全留空</strong>（不要只留换行），让 <code>application.yaml</code> 生效。</li></ul></li></ol><p>保存后重新运行。</p><h3 id="_2-直接修改-idea-workspace-xml-已与仓库修复方式一致" tabindex="-1">2. 直接修改 <code>.idea/workspace.xml</code>（已与仓库修复方式一致） <a class="header-anchor" href="#_2-直接修改-idea-workspace-xml-已与仓库修复方式一致" aria-label="Permalink to &quot;2. 直接修改 \`.idea/workspace.xml\`（已与仓库修复方式一致）&quot;">​</a></h3><p>删除错误的：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ACTIVE_PROFILES&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&amp;#10;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或将其改为合法值，例如：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">option</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ACTIVE_PROFILES&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dev&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意：<code>workspace.xml</code> 可能被 IDE 再次改写，长期习惯上仍以 <strong>Run Configuration 界面</strong> 为准。</p><h3 id="_3-命令行-脚本-ci" tabindex="-1">3. 命令行 / 脚本 / CI <a class="header-anchor" href="#_3-命令行-脚本-ci" aria-label="Permalink to &quot;3. 命令行 / 脚本 / CI&quot;">​</a></h3><p>避免以下写法：</p><ul><li><code>-Dspring.profiles.active=</code>（等号后为空）</li><li>环境变量 <code>SPRING_PROFILES_ACTIVE</code> 被设为空字符串（若走环境变量源，同样可能导致空 profile）</li></ul><p>应显式指定，例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Dspring.profiles.active</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或设置：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SPRING_PROFILES_ACTIVE=dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>（Linux/macOS 使用 <code>export</code>。）</p><h2 id="如何自行判断-是谁覆盖了-yaml" tabindex="-1">如何自行判断“是谁覆盖了 YAML” <a class="header-anchor" href="#如何自行判断-是谁覆盖了-yaml" aria-label="Permalink to &quot;如何自行判断“是谁覆盖了 YAML”&quot;">​</a></h2><p>看报错里的 <strong>Origin</strong> / <strong>property source</strong>：</p><table tabindex="0"><thead><tr><th>来源说明</th><th>常见含义</th></tr></thead><tbody><tr><td><code>systemProperties</code></td><td>JVM 参数 <code>-Dspring.profiles.active=...</code>，常来自 IDE 运行配置或启动脚本</td></tr><tr><td>环境变量相关源</td><td><code>SPRING_PROFILES_ACTIVE</code> 等</td></tr></tbody></table><p>若为 <code>systemProperties</code> 且 Value 为空，优先检查 <strong>IDE 的 Active profiles</strong> 和 <strong>启动命令中的 <code>-D</code> 参数</strong>。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><ul><li><strong>YAML 正常仍可能启动失败</strong>：外部传入的<strong>空</strong> <code>spring.profiles.active</code> 优先级更高。</li><li>本问题典型场景：IDE <strong>Active profiles</strong> 被误设为仅空白/换行，对应 <code>.idea/workspace.xml</code> 里 <code>ACTIVE_PROFILES</code> 为 <code>&amp;#10;</code>。</li><li><strong>修复</strong>：在 IDE 中填写 <code>dev</code> 或清空 Active profiles（无空白占位）；命令行/环境中避免空的 profile 参数。</li></ul>`,38))])}const v=n(d,[["render",c]]);export{E as __pageData,v as default};
